// isNilOrEmpty checks whether a JSON object has nil or empty values for
// common identifier fields (title, name, identifier, id).
// Also checks nested "document" objects for search result wrappers.
func isNilOrEmpty(raw json.RawMessage) bool {
	var obj map[string]interface{}
	if err := json.Unmarshal(raw, &obj); err != nil {
		return true
	}
	// Check top-level fields
	for _, key := range []string{"title", "name", "identifier", "id"} {
		if v, ok := obj[key]; ok {
			if v == nil {
				continue
			}
			if s, ok := v.(string); ok && strings.TrimSpace(s) != "" {
				return false
			}
			// Non-string, non-nil value (e.g. numeric ID) — keep it
			if _, ok := v.(string); !ok {
				return false
			}
		}
	}
	// Check nested "document" for search result wrappers like {score, document: {name, ...}}
	if doc, ok := obj["document"]; ok {
		if docMap, ok := doc.(map[string]interface{}); ok {
			for _, key := range []string{"title", "name", "identifier", "id", "slug"} {
				if v, ok := docMap[key]; ok && v != nil {
					if s, ok := v.(string); ok && strings.TrimSpace(s) != "" {
						return false
					}
					if _, ok := v.(string); !ok {
						return false
					}
				}
			}
		}
	}
	// If the object has a "score" field, it's likely a search result — keep it
	if _, ok := obj["score"]; ok {
		return false
	}
	return true
}

// extractSearchResults unwraps API search responses by checking common envelope paths.
func extractSearchResults(data json.RawMessage) []json.RawMessage {
	// Try direct array first
	var items []json.RawMessage
	if json.Unmarshal(data, &items) == nil {
		return items
	}
	// Try common wrapper paths: data, results, items
	var wrapped map[string]json.RawMessage
	if json.Unmarshal(data, &wrapped) == nil {
		for _, key := range []string{"data", "results", "items", "records", "entries"} {
			if inner, ok := wrapped[key]; ok {
				if json.Unmarshal(inner, &items) == nil {
					return items
				}
			}
		}
	}
	// Return as single-item array
	return []json.RawMessage{data}
}

// PATCH: search command — fix empty case never calling db.Search; add snippet context
// and a meeting-aware result formatter for human-readable output.
func newSearchCmd(flags *rootFlags) *cobra.Command {
	var resourceType string
	var limit int
	var dbPath string

	cmd := &cobra.Command{
		Use:   "search <query>",
		Short: "Full-text search across synced data or live API",
		Long: `Search locally synced data using FTS5 full-text search.
Returns matching meetings with title, date, share URL, and a highlighted
context snippet showing where the query terms appear.

Run 'fathom-pp-cli sync --full' first to populate the local store.`,
		Example: strings.TrimLeft(`
  fathom-pp-cli search "data pipeline"
  fathom-pp-cli search "25 day cycle clearpack" --limit 5
  fathom-pp-cli search "joey action items" --type meetings --json`, "\n"),
		Annotations: map[string]string{"mcp:read-only": "true"},
		RunE: func(cmd *cobra.Command, args []string) error {
			if len(args) == 0 {
				return cmd.Help()
			}
			if dryRunOK(flags) {
				return nil
			}
			query := strings.Join(args, " ")

			if flags.dataSource == "live" {
				return fmt.Errorf("Fathom has no search endpoint; use --data-source local or omit the flag to search locally")
			}

			if dbPath == "" {
				dbPath = defaultDBPath("fathom-pp-cli")
			}
			db, err := store.OpenWithContext(cmd.Context(), dbPath)
			if err != nil {
				return fmt.Errorf("opening local database: %w\nRun 'fathom-pp-cli sync' first", err)
			}
			defer db.Close()

			rows, err := db.DB().QueryContext(cmd.Context(),
				`SELECT
					r.data,
					snippet(resources_fts, 2, '>>>', '<<<', '...', 30) AS snip
				 FROM resources_fts f
				 JOIN resources r ON r.id = f.id
				 WHERE resources_fts MATCH ?
				   AND (? = '' OR f.resource_type = ?)
				 ORDER BY rank
				 LIMIT ?`,
				query, resourceType, resourceType, limit,
			)
			if err != nil {
				return fmt.Errorf("search failed: %w", err)
			}
			defer rows.Close()

			type searchResult struct {
				Title        string `json:"title"`
				Date         string `json:"date,omitempty"`
				URL          string `json:"url,omitempty"`
				ResourceType string `json:"resource_type,omitempty"`
				Snippet      string `json:"snippet"`
			}

			var results []searchResult
			for rows.Next() {
				var raw, snip string
				if err := rows.Scan(&raw, &snip); err != nil {
					continue
				}
				var m fathomMeeting
				sr := searchResult{Snippet: cleanSnippet(snip)}
				if err := json.Unmarshal([]byte(raw), &m); err == nil && m.RecordingID != 0 {
					sr.Title = m.meetingTitle()
					if len(m.CreatedAt) >= 10 {
						sr.Date = m.CreatedAt[:10]
					}
					sr.URL = m.ShareURL
					sr.ResourceType = "meetings"
				} else {
					// generic fallback — extract title/name field
					var obj map[string]interface{}
					if json.Unmarshal([]byte(raw), &obj) == nil {
						for _, k := range []string{"title", "name", "display_name"} {
							if v, ok := obj[k]; ok {
								if s, ok := v.(string); ok {
									sr.Title = s
									break
								}
							}
						}
					}
				}
				if sr.Title == "" {
					sr.Title = "(untitled)"
				}
				results = append(results, sr)
			}
			if err := rows.Err(); err != nil {
				return fmt.Errorf("search scan: %w", err)
			}

			if flags.asJSON || !isTerminal(cmd.OutOrStdout()) {
				return printJSONFiltered(cmd.OutOrStdout(), results, flags)
			}

			if len(results) == 0 {
				fmt.Fprintln(cmd.OutOrStdout(), "No results. Run 'fathom-pp-cli sync --full' if the store is empty.")
				return nil
			}
			fmt.Fprintf(cmd.OutOrStdout(), "%d results for %q\n\n", len(results), query)
			for i, r := range results {
				fmt.Fprintf(cmd.OutOrStdout(), "%d. %s", i+1, r.Title)
				if r.Date != "" {
					fmt.Fprintf(cmd.OutOrStdout(), "  (%s)", r.Date)
				}
				fmt.Fprintln(cmd.OutOrStdout())
				if r.URL != "" {
					fmt.Fprintf(cmd.OutOrStdout(), "   %s\n", r.URL)
				}
				if r.Snippet != "" {
					fmt.Fprintf(cmd.OutOrStdout(), "   %s\n", r.Snippet)
				}
				fmt.Fprintln(cmd.OutOrStdout())
			}
			return nil
		},
	}

	cmd.Flags().StringVar(&resourceType, "type", "", "Filter by resource type (e.g. meetings)")
	cmd.Flags().IntVar(&limit, "limit", 20, "Maximum results to return")
	cmd.Flags().StringVar(&dbPath, "db", "", "Database path")

	return cmd
}

// cleanSnippet strips JSON scaffolding from FTS snippet output so transcript
// text is readable in the terminal. The FTS content field stores the full JSON
// blob, so snippets contain field names, quotes, and braces alongside the
// actual text. This extracts only "text" field values and the marker tokens.
func cleanSnippet(s string) string {
	// Extract "text":"..." values — the human-readable transcript segments
	var parts []string
	rest := s
	for {
		start := strings.Index(rest, `"text":"`)
		if start == -1 {
			break
		}
		rest = rest[start+8:]
		end := strings.Index(rest, `"`)
		if end == -1 {
			break
		}
		part := rest[:end]
		if strings.TrimSpace(part) != "" {
			parts = append(parts, part)
		}
		rest = rest[end:]
	}
	if len(parts) > 0 {
		return strings.Join(parts, " ... ")
	}
	// Fallback: remove JSON keys and keep the marker tokens + surrounding words
	cleaned := strings.NewReplacer(
		`{"`, "", `"}`, "", `","`, " ", `":`, " ", `"`, "",
	).Replace(s)
	return strings.TrimSpace(cleaned)
}

// outputSearchResults filters, counts, and outputs search results with provenance.
func outputSearchResults(cmd *cobra.Command, flags *rootFlags, results []json.RawMessage, limit int, prov DataProvenance) error {
	// Filter out entries with nil or empty identifier fields.
	filtered := make([]json.RawMessage, 0, len(results))
	for _, r := range results {
		if !isNilOrEmpty(r) {
			filtered = append(filtered, r)
		}
	}
	results = filtered

	// Enforce limit across aggregated results.
	if len(results) > limit {
		results = results[:limit]
	}

	jsonMode := flags.asJSON || !isTerminal(cmd.OutOrStdout())

	// JSON mode always emits a valid envelope, including on no matches —
	// agents pipe stdout through json.loads / jq and need parseable output
	// regardless of result count. The filtered slice is built via make
	// above, so it's non-nil even when empty; json.Marshal renders that
	// as `[]` rather than `null`.
	if jsonMode {
		data, err := json.Marshal(results)
		if err != nil {
			return err
		}
		wrapped, err := wrapWithProvenance(data, prov)
		if err != nil {
			return err
		}
		return printOutput(cmd.OutOrStdout(), wrapped, true)
	}

	if len(results) == 0 {
		fmt.Fprintf(cmd.ErrOrStderr(), "No results (source: %s)\n", prov.Source)
		return nil
	}

	printProvenance(cmd, len(results), prov)
	for _, r := range results {
		fmt.Fprintln(cmd.OutOrStdout(), string(r))
	}
	return nil
}
